import jwt
import json
from datetime import datetime
from typing import Dict, Any, Optional, Union


def decode_jwt(
    token: str,
    secret: Optional[str] = None,
    verify: bool = False,
    algorithms: Optional[list] = None,
    audience: Optional[Union[str, list]] = None,
    issuer: Optional[str] = None
) -> Dict[str, Any]:
    """
    Decode and optionally verify a JWT token for debugging purposes.
    
    Args:
        token: The JWT token string to decode
        secret: Secret key for verification (required if verify=True)
        verify: Whether to verify the signature (default: False for debugging)
        algorithms: List of allowed algorithms (default: ['HS256', 'RS256'])
        audience: Expected audience claim
        issuer: Expected issuer claim
    
    Returns:
        Dictionary containing token information including header, payload, and metadata
    """
    
    if algorithms is None:
        algorithms = ['HS256', 'HS384', 'HS512', 'RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512']
    
    result = {
        'valid': False,
        'header': {},
        'payload': {},
        'errors': [],
        'metadata': {}
    }
    
    try:
        # Decode header without verification
        result['header'] = jwt.get_unverified_header(token)
        
        # Decode payload without verification
        unverified_payload = jwt.decode(token, options={"verify_signature": False})
        result['payload'] = unverified_payload
        
        # Add metadata about the token
        if 'exp' in unverified_payload:
            exp_timestamp = unverified_payload['exp']
            exp_datetime = datetime.fromtimestamp(exp_timestamp)
            result['metadata']['expires_at'] = exp_datetime.isoformat()
            result['metadata']['is_expired'] = datetime.now() > exp_datetime
            result['metadata']['time_until_expiry'] = str(exp_datetime - datetime.now())
        
        if 'iat' in unverified_payload:
            iat_timestamp = unverified_payload['iat']
            iat_datetime = datetime.fromtimestamp(iat_timestamp)
            result['metadata']['issued_at'] = iat_datetime.isoformat()
        
        if 'nbf' in unverified_payload:
            nbf_timestamp = unverified_payload['nbf']
            nbf_datetime = datetime.fromtimestamp(nbf_timestamp)
            result['metadata']['not_before'] = nbf_datetime.isoformat()
            result['metadata']['is_active'] = datetime.now() >= nbf_datetime
        
        # If verification is requested
        if verify:
            if secret is None:
                result['errors'].append("Secret key is required for verification")
                return result
            
            try:
                options = {}
                verified_payload = jwt.decode(
                    token,
                    secret,
                    algorithms=algorithms,
                    audience=audience,
                    issuer=issuer,
                    options=options
                )
                result['valid'] = True
                result['payload'] = verified_payload
            except jwt.ExpiredSignatureError:
                result['errors'].append("Token has expired")
            except jwt.InvalidSignatureError:
                result['errors'].append("Invalid signature")
            except jwt.InvalidAudienceError:
                result['errors'].append("Invalid audience")
            except jwt.InvalidIssuerError:
                result['errors'].append("Invalid issuer")
            except jwt.DecodeError as e:
                result['errors'].append(f"Decode error: {str(e)}")
            except Exception as e:
                result['errors'].append(f"Verification error: {str(e)}")
        else:
            result['valid'] = True  # Considered valid if not verifying
            result['metadata']['warning'] = "Signature not verified - for debugging only"
    
    except jwt.DecodeError as e:
        result['errors'].append(f"Failed to decode token: {str(e)}")
    except Exception as e:
        result['errors'].append(f"Unexpected error: {str(e)}")
    
    return result


def print_jwt_info(token: str, secret: Optional[str] = None, verify: bool = False):
    """
    Pretty print JWT token information for debugging.
    
    Args:
        token: The JWT token string to decode
        secret: Secret key for verification
        verify: Whether to verify the signature
    """
    result = decode_jwt(token, secret=secret, verify=verify)
    
    print("=" * 80)
    print("JWT TOKEN INFORMATION")
    print("=" * 80)
    
    print("\n[HEADER]")
    print(json.dumps(result['header'], indent=2))
    
    print("\n[PAYLOAD]")
    print(json.dumps(result['payload'], indent=2))
    
    if result['metadata']:
        print("\n[METADATA]")
        for key, value in result['metadata'].items():
            print(f"  {key}: {value}")
    
    print("\n[VALIDATION]")
    print(f"  Valid: {result['valid']}")
    if result['errors']:
        print("  Errors:")
        for error in result['errors']:
            print(f"    - {error}")
    
    print("=" * 80)


